 19â†’class StatsLinkHandler
 20â†’@Inject constructor(
 21â†’    private val deepLinkUriUtils: DeepLinkUriUtils,
 22â†’    private val jetpackFeatureRemovalPhaseHelper: JetpackFeatureRemovalPhaseHelper
 23â†’) : DeepLinkHandler {
 24â†’    /**
 25â†’     * Builds navigate action from URL like:
 26â†’     * https://wordpress.com/stats/$timeframe/$site
 27â†’     * where timeframe and site are optional
 28â†’     * or
 29â†’     * wordpress://stats
 30â†’     */
 31â†’    override fun buildNavigateAction(uri: UriWrapper): NavigateAction {
 32â†’        val pathSegments = uri.pathSegments
 33â†’        val length = pathSegments.size
 34â†’        val site = pathSegments.getOrNull(length - 1)?.toSite()
 35â†’        val statsTimeframe = pathSegments.getOrNull(length - 2)?.toStatsTimeframe()
 36â†’        return when {
 37â†’            jetpackFeatureRemovalPhaseHelper.shouldShowStaticPage() -> OpenJetpackStaticPosterView
 38â†’            site != null && statsTimeframe != null -> {
 39â†’                OpenStatsForSiteAndTimeframe(site, statsTimeframe)
 40â†’            }
 41â†’            site != null -> {
 42â†’                OpenStatsForSite(site)
 43â†’            }
 44â†’            statsTimeframe != null -> {
 45â†’                OpenStatsForTimeframe(statsTimeframe)
 46â†’            }
 47â†’            else -> {
 48â†’                // In other cases, launch stats with the current selected site.
 49â†’                OpenStats
 50â†’            }
 51â†’        }
 52â†’    }
 53â†’
 54â†’    /**
 55â†’     * Returns true if the URI should be handled by StatsLinkHandler.
 56â†’     * The handled links are `https://wordpress.com/stats/day/$site` and `wordpress://stats`
 57â†’     */
 58â†’    override fun shouldHandleUrl(uri: UriWrapper): Boolean {
 59â†’        return (uri.host == HOST_WORDPRESS_COM &&
 60â†’                uri.pathSegments.firstOrNull() == STATS_PATH) || uri.host == STATS_PATH
 61â†’    }
 62â†’
 63â†’    override fun stripUrl(uri: UriWrapper): String {
 64â†’        return buildString {
 65â†’            val offset = if (uri.host == STATS_PATH) {
 66â†’                append(APPLINK_SCHEME)
 67â†’                0
 68â†’            } else {
 69â†’                append("$HOST_WORDPRESS_COM/")
 70â†’                1
 71â†’            }
 72â†’            append(STATS_PATH)
 73â†’            val pathSegments = uri.pathSegments
 74â†’            val size = pathSegments.size
 75â†’            val statsTimeframe = if (size > offset) pathSegments.getOrNull(offset) else null
 76â†’            val hasSiteUrl = if (size > offset + 1) pathSegments.getOrNull(offset + 1) != null else false
 77â†’            if (statsTimeframe != null) {
 78â†’                append("/$statsTimeframe")
 79â†’            }
 80â†’            if (hasSiteUrl) {
 81â†’                append("/$SITE_DOMAIN")
 82â†’            }
 83â†’        }
 84â†’    }
 85â†’
 86â†’    /**
 87â†’     * Converts HOST name of a site to SiteModel. It finds the Site in the current local sites and matches the name
 88â†’     * to the host.
 89â†’     */
 90â†’    private fun String.toSite(): SiteModel? {
 91â†’        return deepLinkUriUtils.hostToSite(this)
 92â†’    }
 93â†’
 94â†’    private fun String.toStatsTimeframe(): StatsTimeframe? {
 95â†’        return when (this) {
 96â†’            "day" -> StatsTimeframe.DAY
 97â†’            "week" -> StatsTimeframe.WEEK
 98â†’            "month" -> StatsTimeframe.MONTH
 99â†’            "year" -> StatsTimeframe.YEAR
100â†’            "insights" -> StatsTimeframe.INSIGHTS
101â†’            else -> null
102â†’        }
103â†’    }
104â†’
105â†’    companion object {
106â†’        private const val STATS_PATH = "stats"
107â†’    }
108â†’}
